import requestsfrom data_processor import build_ohlc_dataframe, empty_ohlc_dataframedef fetch_data(days):    """    Fetch Bitcoin OHLC data from the CoinGecko API.    Returns a Pandas DataFrame with Open, High, Low, Close and Volume columns.    """    print(f"Fetching Bitcoin data for: {days} days")    url = (        "https://api.coingecko.com/api/v3/coins/bitcoin/ohlc"        f"?vs_currency=usd&days={days}"    )    headers = {        "User-Agent": "bitcoin-price-chart-visualiser/1.0"    }    try:        timeout_seconds = 20 if days == "max" else 8        response = requests.get(url, headers=headers, timeout=timeout_seconds)        response.raise_for_status()        raw_data = response.json()        df = build_ohlc_dataframe(raw_data)        print(f"Fetched {len(df)} rows")        return df    except requests.exceptions.RequestException as error:        print(f"API request failed: {error}")        return empty_ohlc_dataframe()    except Exception as error:        print(f"Data processing failed: {error}")        return empty_ohlc_dataframe()